import{c as a,Q as t,j as s,m as r}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"Meta-Harness: End-to-End Optimization of Model Harnesses","description":"","frontmatter":{"title":"Meta-Harness: End-to-End Optimization of Model Harnesses","arxiv_id":2603.28052,"authors":"Yoonho Lee, Roshen Nair, Qizheng Zhang, Kangwook Lee, Omar Khattab, Chelsea Finn","fetched":"2026-05-12T00:00:00.000Z","published":"2026-03-30T00:00:00.000Z","source":"https://arxiv.org/abs/2603.28052","source_tier":"P"},"headers":[],"relativePath":"research/agent-harness/references/2026-05-12-meta-harness-2603-28052.md","filePath":"research/agent-harness/references/2026-05-12-meta-harness-2603-28052.md","lastUpdated":1779901665000}'),i={name:"research/agent-harness/references/2026-05-12-meta-harness-2603-28052.md"};function n(o,e,l,c,d,h){return t(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="meta-harness-end-to-end-optimization-of-model-harnesses" tabindex="-1">Meta-Harness: End-to-End Optimization of Model Harnesses <a class="header-anchor" href="#meta-harness-end-to-end-optimization-of-model-harnesses" aria-label="Permalink to &quot;Meta-Harness: End-to-End Optimization of Model Harnesses&quot;">​</a></h1><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>The paper introduces Meta-Harness, a system that automatically searches for improved code harnesses—the execution frameworks that determine what information language models access and process. Rather than relying on manual engineering, Meta-Harness employs an agentic proposer with filesystem access to prior candidates&#39; source code, execution traces, and performance scores.</p><p>Key findings include: on text classification, discovered harnesses outperform state-of-the-art manual designs by 7.7 points while consuming 4× fewer context tokens; on mathematical reasoning, a single harness improves IMO-level problem accuracy by 4.7 points across five models; on TerminalBench-2 coding tasks, automated harnesses rank #1 among Claude Haiku 4.5 agents.</p><hr><h2 id="core-contribution" tabindex="-1">Core Contribution <a class="header-anchor" href="#core-contribution" aria-label="Permalink to &quot;Core Contribution&quot;">​</a></h2><p>Meta-Harness addresses a fundamental limitation in existing text optimization approaches: they compress feedback too aggressively through scalar scores, brief summaries, or restricted templates. This paper argues that &quot;useful context should often be accessed adaptively&quot; rather than packed into single prompts. The system provides &quot;full access to execution traces&quot; enabling proposers to form causal hypotheses about failures and test targeted fixes.</p><hr><h2 id="technical-approach" tabindex="-1">Technical Approach <a class="header-anchor" href="#technical-approach" aria-label="Permalink to &quot;Technical Approach&quot;">​</a></h2><p><strong>Search Loop:</strong> The system iteratively:</p><ol><li>Proposer inspects filesystem containing prior harness code, scores, and traces</li><li>Generates new harness candidates</li><li>Evaluates and logs results with full diagnostic information</li><li>Repeats for fixed iterations</li></ol><p><strong>Key Design Choice:</strong> Rather than summarizing history, the filesystem stores complete artifacts. The proposer queries these via standard tools (grep, cat), reading a median of 82 files per iteration and referencing over 20 prior candidates per step.</p><p><strong>Scale:</strong> Individual evaluations generate up to 10 million tokens of diagnostic data—roughly &quot;three orders of magnitude beyond&quot; prior text optimization work.</p><hr><h2 id="experimental-results" tabindex="-1">Experimental Results <a class="header-anchor" href="#experimental-results" aria-label="Permalink to &quot;Experimental Results&quot;">​</a></h2><h3 id="text-classification-4-datasets" tabindex="-1">Text Classification (4 Datasets) <a class="header-anchor" href="#text-classification-4-datasets" aria-label="Permalink to &quot;Text Classification (4 Datasets)&quot;">​</a></h3><ul><li><strong>Improvement over ACE baseline:</strong> 7.7 percentage points</li><li><strong>Context reduction:</strong> 4× fewer tokens (11.4K vs 50.8K)</li><li><strong>Speed advantage:</strong> Matches competing optimizers&#39; final performance in 0.1× evaluations</li><li><strong>Generalization:</strong> Outperforms hand-designed systems on 9 held-out OOD datasets (73.1% avg accuracy)</li></ul><h3 id="mathematical-reasoning-200-imo-level-problems" tabindex="-1">Mathematical Reasoning (200 IMO-Level Problems) <a class="header-anchor" href="#mathematical-reasoning-200-imo-level-problems" aria-label="Permalink to &quot;Mathematical Reasoning (200 IMO-Level Problems)&quot;">​</a></h3><ul><li><strong>Average gain over no retrieval:</strong> 4.7 points</li><li><strong>Model transfer:</strong> Single harness improves performance across GPT-5.4-nano, GPT-5.4-mini, Gemini-3.1-Flash-Lite, Gemini-3-Flash, and GPT-OSS-20B</li><li><strong>Approach:</strong> Discovered routing logic directing problems to subject-specific retrieval policies</li></ul><h3 id="terminalbench-2-agentic-coding" tabindex="-1">TerminalBench-2 Agentic Coding <a class="header-anchor" href="#terminalbench-2-agentic-coding" aria-label="Permalink to &quot;TerminalBench-2 Agentic Coding&quot;">​</a></h3><ul><li><strong>Opus 4.6 performance:</strong> 76.4% pass rate (surpasses Terminus-KIRA at 74.7%)</li><li><strong>Haiku 4.5 ranking:</strong> #1 among reported agents (37.6% vs prior best 35.5%)</li><li><strong>Main discovery:</strong> Environment bootstrapping reducing exploratory turns by 2-4 steps</li></ul><hr><h2 id="ablation-studies" tabindex="-1">Ablation Studies <a class="header-anchor" href="#ablation-studies" aria-label="Permalink to &quot;Ablation Studies&quot;">​</a></h2><p>The paper demonstrates that raw execution trace access is essential. Compared to scores-only and scores-plus-summary approaches:</p><ul><li>Scores only: 34.6 median accuracy</li><li>Scores + summaries: 34.9 median accuracy</li><li>Full traces: 50.0 median accuracy</li></ul><p>This reveals that &quot;summaries do not recover the missing signal&quot; and may actively harm optimization through information compression.</p><hr><h2 id="qualitative-analysis" tabindex="-1">Qualitative Analysis <a class="header-anchor" href="#qualitative-analysis" aria-label="Permalink to &quot;Qualitative Analysis&quot;">​</a></h2><p>The TerminalBench-2 search trajectory reveals sophisticated causal reasoning. The proposer explicitly identified confounded interventions across regressions, hypothesized that prompt modifications (not structural bugfixes) caused failures, tested the hypothesis by isolating variables, and pivoted toward purely additive changes after observing repeated patterns.</p><hr><h2 id="technical-implementation" tabindex="-1">Technical Implementation <a class="header-anchor" href="#technical-implementation" aria-label="Permalink to &quot;Technical Implementation&quot;">​</a></h2><ul><li><strong>Proposer:</strong> Claude Code with Opus-4.6</li><li><strong>Base models:</strong> Frozen; vary by domain (GPT-OSS models, Claude variants)</li><li><strong>Harness representation:</strong> Single-file Python programs modifying prompting, retrieval, memory, and orchestration</li><li><strong>Typical run:</strong> ~60 harnesses evaluated over 20 iterations</li><li><strong>Wall-clock time:</strong> Several hours producing readable, transferable strategies</li></ul><hr><h2 id="related-work-positioning" tabindex="-1">Related Work Positioning <a class="header-anchor" href="#related-work-positioning" aria-label="Permalink to &quot;Related Work Positioning&quot;">​</a></h2><p>Meta-Harness extends three research areas:</p><ol><li><p><strong>Adaptive context access</strong> (RAG, interleaved retrieval, memory-augmented systems) applied to harness engineering rather than end-user reasoning</p></li><li><p><strong>Executable code search</strong> over program functions and agent designs, but with unrestricted filesystem access rather than predefined scaffolds</p></li><li><p><strong>Text optimization</strong> (TextGrad, OPRO, GEPA, AlphaEvolve), but operating at orders-of-magnitude larger information scales with selective rather than monolithic access</p></li></ol><hr><h2 id="discovered-harness-examples" tabindex="-1">Discovered Harness Examples <a class="header-anchor" href="#discovered-harness-examples" aria-label="Permalink to &quot;Discovered Harness Examples&quot;">​</a></h2><p><strong>Text Classification:</strong> Two complementary strategies emerged:</p><ul><li>Draft-verification: Two-call procedure retrieving confirmers and challengers</li><li>Label-primed query: Single call exposing label space with contrastive local boundaries</li></ul><p><strong>Math Reasoning:</strong> Four-route lexical router assigning problems to subject-specific BM25 policies with problem-specific deduplication and reranking</p><p><strong>Coding Tasks:</strong> Environment bootstrapping gathering OS metadata before initial LLM turn, reducing wasteful exploration</p><hr><h2 id="limitations-and-future-work" tabindex="-1">Limitations and Future Work <a class="header-anchor" href="#limitations-and-future-work" aria-label="Permalink to &quot;Limitations and Future Work&quot;">​</a></h2><p>The authors note the study focuses on one strong proposer (Claude Code) and suggest broader analysis across agents remains valuable. They propose co-evolving harnesses and model weights as natural next steps. The TerminalBench-2 harness, while benchmark-specialized, targets fundamental long-horizon task completion capabilities.</p><hr><h2 id="practical-impact" tabindex="-1">Practical Impact <a class="header-anchor" href="#practical-impact" aria-label="Permalink to &quot;Practical Impact&quot;">​</a></h2><p>Discovered harnesses demonstrate genuine transferability: text classification harness generalizes to unseen domains; math retrieval harness improves multiple held-out base models; harnesses produce inspectable code enabling straightforward overfitting detection compared to weight-space optimization.</p>',48)])])}const u=a(i,[["render",n]]);export{m as __pageData,u as default};
